class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.handlers: Dict[str, MessageHandler] = {}
        self.running = False
        
        self._register_default_handlers()
    
    def _register_default_handlers(self):
        self.register_handler('email', EmailHandler())
        self.register_handler('data_processing', DataProcessingHandler())
        self.register_handler('notification', NotificationHandler())
        self.register_handler('report_generation', ReportGenerationHandler())
        self.register_handler('image_processing', ImageProcessingHandler())
        self.register_handler('webhook', WebhookHandler())
        self.register_handler('database_cleanup', DatabaseCleanupHandler())
        self.register_handler('default', DefaultHandler())
    
    def register_handler(self, message_type: str, handler: MessageHandler):
        self.handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
    
    def poll_messages(self) -> list:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            return response.get('Messages', [])
        except Exception as e:
            logger.error(f"Error polling messages: {str(e)}")
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            body = message.get('Body', '{}')
            parsed_body = json.loads(body)
            
            message_data = {
                'message_id': message.get('MessageId'),
                'receipt_handle': message.get('ReceiptHandle'),
                'type': parsed_body.get('type', 'default'),
                'data': parsed_body.get('data', {}),
                'timestamp': parsed_body.get('timestamp', datetime.utcnow().isoformat()),
                'attributes': message.get('Attributes', {}),
                'message_attributes': message.get('MessageAttributes', {})
            }
            
            return message_data
        except json.JSONDecodeError as e:
            logger.error(f"Error parsing message body: {str(e)}")
            return None
        except Exception as e:
            logger.error(f"Unexpected error parsing message: {str(e)}")
            return None
    
    def process_message(self, message_data: Dict[str, Any]) -> bool:
        message_type = message_data.get('type', 'default')
        data = message_data.get('data', {})
        
        logger.info(f"Processing message {message_data['message_id']} of type '{message_type}'")
        
        handler = self.handlers.get(message_type, self.handlers.get('default'))
        
        try:
            result = handler.handle(data)
            if result:
                logger.info(f"Successfully processed message {message_data['message_id']}")
            else:
                logger.warning(f"Handler returned False for message {message_data['message_id']}")
            return result
        except Exception as e:
            logger.error(f"Error processing message {message_data['message_id']}: {str(e)}")
            return False
    
    def delete_message(self, receipt_handle: str) -> bool:
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info(f"Deleted message from queue")
            return True
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
            return False
    
    def change_message_visibility(self, receipt_handle: str, timeout: int) -> bool:
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
            return True
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
            return False
    
    def process_batch(self, messages: list):
        for message in messages:
            message_data = self.parse_message(message)
            
            if message_data is None:
                logger.error(f"Skipping invalid message")
                continue
            
            success = self.process_message(message_data)
            
            if success:
                self.delete_message(message_data['receipt_handle'])
            else:
                logger.warning(f"Message processing failed, will retry after visibility timeout")
    
    def start(self):
        self.running = True
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        while self.running:
            try:
                messages = self.poll_messages()
                
                if messages:
                    logger.info(f"Received {len(messages)} message(s)")
                    self.process_batch(messages)
                else:
                    logger.debug("No messages received")
                
            except KeyboardInterrupt:
                logger.info("Received interrupt signal, shutting down...")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {str(e)}")
                time.sleep(5)
    
    def stop(self):
        self.running = False
        logger.info("SQS worker stopped")


